1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	export function claimOffice(input: any): unknown {
13	  const items = input.steps[0].items;
14	  let basePremium = items.reduce(
15	    (sum: number, item: any) => sum + BASE_PREMIUMS[item.type],
16	    0
17	  );
18	
19	  const typeCounts: Record<string, number> = {};
20	  for (const item of items) {
21	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
22	  }
23	  for (const type in typeCounts) {
24	    if (typeCounts[type] === 3) {
25	      basePremium = basePremium - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
26	    }
27	  }
28	
29	  const premium = basePremium + PROCESSING_FEE;
30	  return { results: [{ premium }] };
31	}
